    function _buildFullSVG(uint256 tokenId, uint64 g, uint64 k, uint64 d, uint64 a) internal view returns (string memory) {
        PlayerData memory p = s_playerData[tokenId];
        
        uint64 deaths = d == 0 ? 1 : d;
        uint256 kdaValue = (uint256(k) + uint256(a)) * 100 / deaths;
        string memory kdaStr = string.concat((kdaValue / 100).toString(), ".", (kdaValue % 100).toString());

        return string.concat(
