        require(err.length == 0, "Oracle Error");
        uint256 tokenId = s_requestToTokenId[requestId];
        uint256 packedData = abi.decode(response, (uint256));
        
        uint64 a = uint64(packedData);
        uint64 d = uint64(packedData >> 64);
        uint64 k = uint64(packedData >> 128);
        uint64 g = uint64(packedData >> 192);

        s_playerData[tokenId].assists = a;
        s_playerData[tokenId].deaths = d;
        s_playerData[tokenId].kills = k;
        s_playerData[tokenId].games = g;

        // MODEL A BEHAVIOR: Menimpa ulang state storage `fullSvg` dengan string raksasa
        s_playerData[tokenId].fullSvg = _buildFullSVG(tokenId, g, k, d, a);
    }

    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        // Hanya memanggil data yang sudah tersimpan statis di storage
        string memory storedSvg = s_playerData[tokenId].fullSvg;
        string memory imageBase64 = Base64.encode(bytes(storedSvg));
        
        string memory json = Base64.encode(
            bytes(
                string.concat(
                    '{"name": "Kartu Non-Optimized #', tokenId.toString(), '", ',
                    '"description": "Kartu dNFT MPL (Model A). Menggunakan memori State Storage secara penuh untuk pembuktian riset.", ',
                    '"image": "data:image/svg+xml;base64,', imageBase64, '"}'
                )
            )
        );
        return string.concat("data:application/json;base64,", json);
    }

    function checkUpkeep(bytes calldata) external view returns (bool upkeepNeeded, bytes memory performData) {
        upkeepNeeded = (block.timestamp - lastTimeStamp) > interval && targetTokenIdToUpdate < _tokenIds;
        performData = bytes("");
    }

    function performUpkeep(bytes calldata) external {
        if ((block.timestamp - lastTimeStamp) > interval) {
            lastTimeStamp = block.timestamp;
            _requestStatsInternal(targetTokenIdToUpdate, s_playerData[targetTokenIdToUpdate].name);
        }
    }
